const orders = [];
const regions = ['Ha Noi', 'Da Nang', 'Ho Chi Minh'];
const names = ['Nguyen Van A', 'Tran Thi B', 'Le Van C'];

const count = Math.floor(Math.random() * 3) + 1;

for (let i = 0; i < count; i++) {
  orders.push({
    order_code: 'ORD-' + Date.now() + '-' + i,
    customer_name: names[Math.floor(Math.random() * names.length)],
    total_amount: Math.floor(Math.random() * 500000) + 100000,
    status: 'completed',
    region: regions[Math.floor(Math.random() * regions.length)],
    created_at: new Date().toISOString(),
  });
}

return orders.map((o) => ({ json: o }));
